            {{-- ── Footer (editable via Settings → Notifications → Email Footer Text) ── --}}
            @php
                $footerText = \Dcplibrary\Sfp\Models\Setting::get(
                    'email_footer_text',
                    'Please do not reply to this message. Replies will not be routed to or seen by library staff.'
                );
            @endphp
            <tr>
                <td style="padding:16px 28px;background-color:#ffffff;border-top:1px solid #e2e8f0;
                            font-size:12px;color:#94a3b8;line-height:1.6;text-align:center;">
                    {!! nl2br(e($footerText)) !!}
                </td>
            </tr>

